import { useState, useEffect } from "react";
import AdminLayout from "../../AdminLayout";
import "./AddPatient.css";

// --- Country & City Data (sample – extendable) ---
const countryCityMap = {
  India: ["Delhi", "Mumbai", "Bangalore", "Chennai", "Hyderabad"],
  UAE: ["Dubai", "Abu Dhabi", "Sharjah", "Ajman"],
  USA: ["New York", "Los Angeles", "Chicago", "Houston"],
  UK: ["London", "Manchester", "Birmingham"],
};

export default function AddPatient() {
  const [dob, setDob] = useState("");
  const [age, setAge] = useState("");
  const [country, setCountry] = useState("");
  const [cityList, setCityList] = useState([]);
  const [photo, setPhoto] = useState(null);

  // ✅ Real-time age calculation
  useEffect(() => {
    if (!dob) return;
    const birthDate = new Date(dob);
    const today = new Date();

    let calculatedAge = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();

    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
      calculatedAge--;
    }
    setAge(calculatedAge);
  }, [dob]);

  // ✅ Country → City dependency
  const handleCountryChange = (value) => {
    setCountry(value);
    setCityList(countryCityMap[value] || []);
  };

  return (
    <AdminLayout>
      <div className="patient-page">

        {/* Header */}
        <div className="patient-header">
          <div>
            <h2>Patient Registration</h2>
            <p>HL7 v2.5 • ADT A04</p>
          </div>

          {/* Passport Photo */}
          <div className="photo-box">
            {photo ? <img src={photo} alt="patient" /> : <span>Upload Photo</span>}
            <input
              type="file"
              accept="image/*"
              onChange={(e) => setPhoto(URL.createObjectURL(e.target.files[0]))}
            />
          </div>
        </div>

        {/* Main Card */}
        <div className="patient-card">

          {/* Patient Info */}
          <section>
            <h3>Patient Information</h3>
            <div className="grid">
              <div>
                <label>MRN</label>
                <input placeholder="MRN123" />
              </div>

              <div>
                <label>First Name</label>
                <input />
              </div>

              <div>
                <label>Last Name</label>
                <input />
              </div>

              <div>
                <label>Display Name</label>
                <input />
              </div>

              <div>
                <label>Date of Birth</label>
                <input type="date" value={dob} onChange={(e) => setDob(e.target.value)} />
              </div>

              <div>
                <label>Age</label>
                <input value={age} readOnly />
              </div>

              <div>
                <label>Gender</label>
                <select>
                  <option>Male</option>
                  <option>Female</option>
                </select>
              </div>

              <div>
                <label>Marital Status</label>
                <select>
                  <option>Single</option>
                  <option>Married</option>
                </select>
              </div>
            </div>
          </section>

          {/* Contact Details */}
          <section>
            <h3>Contact Details</h3>
            <div className="grid">
              <div>
                <label>Address</label>
                <input />
              </div>

              <div>
                <label>Country</label>
                <select value={country} onChange={(e) => handleCountryChange(e.target.value)}>
                  <option value="">Select Country</option>
                  {Object.keys(countryCityMap).map((c) => (
                    <option key={c}>{c}</option>
                  ))}
                </select>
              </div>

              <div>
                <label>City</label>
                <select>
                  <option>Select City</option>
                  {cityList.map((city) => (
                    <option key={city}>{city}</option>
                  ))}
                </select>
              </div>

              <div>
                <label>Mobile Number</label>
                <input placeholder="+91 9876543210" />
              </div>

              <div>
                <label>National ID Number</label>
                <input />
              </div>
            </div>
          </section>

          {/* Emergency */}
          <section>
            <h3>Emergency Contact</h3>
            <div className="grid">
              <div>
                <label>First Name</label>
                <input />
              </div>
              <div>
                <label>Last Name</label>
                <input />
              </div>
              <div>
                <label>Mobile</label>
                <input />
              </div>
            </div>
          </section>

          <div className="actions">
            <button className="submit">Register Patient</button>
          </div>
        </div>
      </div>
    </AdminLayout>
  );
}
